#include <iostream>
#include <string>

const std::string& getLabel(int n) {
    static const std::string pos{ "positive" };
    static const std::string neg{ "negative" };
    static const std::string zer{ "zero" };
    if (n > 0) return pos;
    if (n < 0) return neg;
    return zer;
}

int main() {
    int n{};
    while (std::cin >> n) {
        std::cout << getLabel(n) << '\n';
    }
    return 0;
}

