exercises.solution_code:
#include <iostream>
#include <string>

const std::string* getGrade(int score) {
    static const std::string a{ "A" };
    static const std::string b{ "B" };
    static const std::string c{ "C" };
    static const std::string d{ "D" };
    static const std::string f{ "F" };

    if (score < 0 || score > 100) return nullptr;
    if (score >= 90) return &a;
    if (score >= 80) return &b;
    if (score >= 70) return &c;
    if (score >= 60) return &d;
    return &f;
}

int main() {
    int q{};
    std::cin >> q;

    while (q-- > 0) {
        int score{};
        std::cin >> score;
        const std::string* grade { getGrade(score) };
        if (grade)
            std::cout << "Score " << score << ": " << *grade << '\n';
        else
            std::cout << "Score " << score << ": invalid\n";
    }
    return 0;
}
